  function ruleReportMarkup(report){if(!report)return'';const relaxed=report.relaxedPreferences||[];const warnings=report.warnings||[];const checks=report.debutChecks||[];const checkHtml=checks.length?`<div class="calendar-debut-checks"><h4>Controllo vincoli di esordio</h4><table><thead><tr><th>Squadra</th><th>Vincolo</th><th>Richiesto</th><th>Ottenuto</th><th>Esito</th></tr></thead><tbody>${checks.map(c=>`<tr><td>${UI.esc(c.team)}</td><td>${UI.esc(c.rule)}</td><td>${UI.esc(c.requested)}</td><td>${UI.esc(c.obtained)}</td><td><span class="calendar-report-row ${c.ok?'ok':'warn'}">${UI.esc(c.status)}</span></td></tr>`).join('')}</tbody></table></div>`:'';return `<section class="calendar-rule-report"><h3>Riepilogo delle regole</h3><div class="calendar-report-grid"><div><h4>Regole rispettate</h4>${(report.respectedHardConstraints||[]).map(x=>`<span class="calendar-report-row ok">${UI.esc(x)}</span>`).join('')}</div><div><h4>Preferenze rispettate</h4>${(report.satisfiedPreferences||[]).map(x=>`<span class="calendar-report-row ok">${UI.esc(x)}</span>`).join('')}</div><div><h4>Preferenze rilassate</h4>${relaxed.length?relaxed.map(r=>`<span class="calendar-report-row warn"><strong>${UI.esc(r.rule)}</strong><small>${UI.esc(r.reason)} ${UI.esc(r.effect||'')}</small></span>`).join(''):'<span class="calendar-report-row ok">Nessuna preferenza rilassata.</span>'}</div></div>${checkHtml}${warnings.length?`<div class="calendar-conflict-list">${warnings.map(w=>`<div class="calendar-conflict warn"><strong>${UI.esc(w.rule)}</strong><span>${UI.esc(w.message)}</span></div>`).join('')}</div>`:''}</section>`;}
  function conflictActions(c){if(!c.actions?.length)return'';return `<div class="calendar-conflict-actions"><button class="btn small" type="button" data-conflict-prefer="${UI.esc(c.sourceType)}:${UI.esc(c.sourceId)}">Trasforma in preferenza</button><button class="btn danger small" type="button" data-conflict-remove="${UI.esc(c.sourceType)}:${UI.esc(c.sourceId)}">Rimuovi regola</button></div>`;}
  function infeasibleMarkup(p){const conflicts=p.conflicts||p.issues||[];const canSimplify=p.simplificationAvailable!==false;const conflictHtml=conflicts.length?conflicts.map(c=>`<div class="calendar-conflict ${c.nonRelaxable?'hard':''}"><strong>${UI.esc(c.rule||'Vincolo')}</strong><span>${UI.esc(c.message||'Vincolo non rispettato.')}</span><small>Suggerimento: ${UI.esc(c.suggestion||'Modifica la regola e riesegui la validazione.')}</small>${conflictActions(c)}</div>`).join(''):`<div class="calendar-conflict hard"><strong>Pianificazione</strong><span>${UI.esc(p.message||'Nessuna soluzione valida trovata.')}</span></div>`;const simplifyBtn=canSimplify?'<button class="btn" type="button" data-calendar-simplify>Genera calendario semplificato</button>':'';return `<div class="calendar-infeasible-panel"><h3>Impossibile generare il calendario personalizzato</h3><p>Non e possibile generare il calendario rispettando contemporaneamente tutte le regole obbligatorie selezionate. I dati del torneo non sono stati modificati e nessuna partita e stata salvata.</p><div class="calendar-conflict-list">${conflictHtml}</div><div class="calendar-wizard-actions inline"><button class="btn primary" type="button" data-calendar-edit-rules>Modifica le regole</button>${simplifyBtn}<button class="btn danger" type="button" data-calendar-cancel>Annulla</button></div></div>`;}
