  function previewStep(){if(wizard.simplificationReview)return simplificationReviewMarkup();if(wizard.previewStale)return `<div class="calendar-infeasible-panel"><h3>Anteprima obsoleta</h3><p>I vincoli di esordio sono stati modificati. Il calendario deve essere ricalcolato completamente prima di poter essere confermato.</p><div class="calendar-wizard-actions inline"><button class="btn primary" type="button" data-calendar-preview>Ricalcola l intero calendario</button><button class="btn" type="button" data-calendar-edit-rules>Modifica le regole</button></div></div>`;if(!wizard.preview)wizard.preview=store.previewCalendar(wizard.draft,{alternate:wizard.alternate});const p=wizard.preview;const draft=p.draft||wizard.draft;if(!p.ok)return infeasibleMarkup(p);const simplified=p.status==='SIMPLIFIED_SOLUTION';const actions=simplified?'<div class="calendar-wizard-actions inline"><button class="btn" type="button" data-calendar-modify-proposal>Modifica proposta</button><button class="btn" type="button" data-calendar-edit-rules>Torna alle regole</button><button class="btn" type="button" data-calendar-regenerate-simplified>Genera un altra proposta</button></div>':'';const issues=p.validation?.issues||p.issues||[];const issueHtml=issues.length?issues.map(i=>`<div class="calendar-conflict ${i.severity==='error'?'':'warn'}"><strong>${UI.esc(i.rule||'Vincolo')}</strong><span>${UI.esc(i.message)}</span></div>`).join(''):'<div class="calendar-check ok"><strong>Fattibile</strong><span>Nessun conflitto rigido rilevato.</span></div>';return `<div class="calendar-preview-grid"><div><div class="message ${simplified?'warn':'ok'}"><strong>${simplified?'Anteprima calendario semplificato':'Anteprima calendario'}</strong><br>${UI.esc(p.message)}</div><div class="calendar-preview-list stack margin-top">${UI.matchList(draft,p.previewMatches,false)}</div>${ruleReportMarkup(p.ruleReport)}${actions}</div><aside><h3>Report fattibilita</h3>${issueHtml}</aside></div>`;}
  function renderWizard(){const modal=ensureWizard(),box=UI.$('#calendarWizardContent');const body=[prereqStep,preferencesStep,firstRoundStep,constraintsStep,previewStep][wizard.step]();const draftNote=wizard.loadedDraft?`<div class="message ok">Bozza calendario recuperata${wizard.savedAt?' · '+UI.esc(new Date(wizard.savedAt).toLocaleString('it-IT')):''}. Puoi modificarla, salvarla, eliminarla o generare dall anteprima.</div>`:'';box.innerHTML=`${draftNote}<div class="calendar-wizard-steps">${steps.map((s,i)=>`<button class="calendar-wizard-step ${i===wizard.step?'active':''}" type="button" data-calendar-step="${i}">${i+1}. ${UI.esc(s)}</button>`).join('')}</div><div class="calendar-wizard-body">${body}</div><div class="calendar-wizard-actions"><button class="btn" type="button" data-calendar-prev ${wizard.step===0?'disabled':''}>Indietro</button><div class="row-actions"><button class="btn" type="button" data-calendar-save-draft>Salva bozza</button><button class="btn danger" type="button" data-calendar-clear-draft>Elimina bozza</button><button class="btn" type="button" data-calendar-preview>${wizard.previewStale?'Ricalcola l intero calendario':'Analizza fattibilita'}</button>${wizard.step<4?'<button class="btn primary" type="button" data-calendar-next>Avanti</button>':`<button class="btn primary" type="button" data-calendar-confirm ${!(wizard.preview&&wizard.preview.ok)||wizard.previewStale||wizard.running?'disabled':''}>Conferma e crea calendario</button>`}</div></div>`;modal.querySelector('.calendar-wizard-step.active')?.focus?.({preventScroll:true});}
  function syncWizardFromDom(){if(!wizard.draft)return;const c=store.normalizeCalendarCustomization(wizard.draft.rules.calendarCustomization);const profile=UI.$('[data-cal-field="profile"]');if(profile)c.profile=profile.value;const seed=UI.$('[data-cal-field="seed"]');if(seed)c.seed=seed.value.trim();const rest=UI.$('[data-cal-field="minRestMinutes"]');if(rest)c.minRestMinutes=Number(rest.value)||0;const balance=UI.$('[data-cal-field="balanceFields"]');if(balance)c.preferences.balanceFields=balance.checked;UI.$$('#calendarWizardModal [data-lock-index]').forEach(row=>{const i=Number(row.dataset.lockIndex),lock=c.firstRoundLocks[i];if(!lock)return;row.querySelectorAll('[data-lock-field]').forEach(input=>lock[input.dataset.lockField]=input.value);});UI.$$('#calendarWizardModal [data-debut-index]').forEach(row=>{const i=Number(row.dataset.debutIndex),rule=c.teamDebuts[i];if(!rule)return;row.querySelectorAll('[data-debut-field]').forEach(input=>rule[input.dataset.debutField]=input.value);});UI.$$('#calendarWizardModal [data-unav-index]').forEach(row=>{const i=Number(row.dataset.unavIndex),rule=c.teamUnavailability[i];if(!rule)return;row.querySelectorAll('[data-unav-field]').forEach(input=>rule[input.dataset.unavField]=input.value);});UI.$$('#calendarWizardModal [data-fieldblock-index]').forEach(row=>{const i=Number(row.dataset.fieldblockIndex),rule=c.fieldBlocks[i];if(!rule)return;row.querySelectorAll('[data-fieldblock-field]').forEach(input=>rule[input.dataset.fieldblockField]=input.value);});wizard.draft.rules.calendarCustomization=store.normalizeCalendarCustomization(c);}
  function applyConflictAction(raw,action){if(!raw||!wizard.draft)return;syncWizardFromDom();const [type,id]=String(raw).split(':');const c=wizard.draft.rules.calendarCustomization;if(type==='firstRoundLock'){const i=c.firstRoundLocks.findIndex(x=>x.id===id);if(i>=0){if(action==='prefer')c.firstRoundLocks[i].mode='preferred';if(action==='remove')c.firstRoundLocks.splice(i,1);wizard.step=2;}}if(type==='teamDebut'){const i=c.teamDebuts.findIndex(x=>x.id===id);if(i>=0){if(action==='prefer')c.teamDebuts[i].mode='preferred';if(action==='remove')c.teamDebuts.splice(i,1);wizard.step=3;}}wizard.preview=null;wizard.simplificationReview=false;wizard.draft.rules.calendarCustomization=store.normalizeCalendarCustomization(c);saveCalendarDraft({silent:true});renderWizard();}
  function confirmCalendar(){syncWizardFromDom();if(wizard.previewStale){wizard.step=4;renderWizard();return;}const preview=wizard.preview&&wizard.preview.ok?wizard.preview:store.previewCalendar(wizard.draft,{alternate:wizard.alternate});wizard.preview=preview;if(!preview.ok){renderWizard();return;}const old=A.state();const hasReports=old.matches.some(m=>(m.goals&&m.goals.length)||(m.cards&&m.cards.length)||m.status==='played'||m.status==='live');if(hasReports&&!confirm('Esistono referti o risultati. Confermando sostituirai il calendario e i referti non compatibili potrebbero essere persi. Continuare?'))return;wizard.running=true;renderWizard();let res;const s=A.state();readInto(s);if(preview.status==='SIMPLIFIED_SOLUTION'){s.rules.calendarCustomization=preview.simplifiedCalendarCustomization;s.rules.calendarSimplification={status:'SIMPLIFIED_SOLUTION',level:preview.simplificationLevel,originalCalendarCustomization:preview.originalCalendarCustomization,simplifiedCalendarCustomization:preview.simplifiedCalendarCustomization,relaxedPreferences:preview.relaxedPreferences||[],attempts:preview.attempts||[],validatedAt:new Date().toISOString(),seed:preview.calendarVariant||preview.simplifiedCalendarCustomization?.seed||''};s.rules.calendarVariant=preview.calendarVariant||s.rules.calendarVariant||'';res=store.generateCalendar(s,{preserveResults:false,alternate:false});}else{s.rules.calendarCustomization=wizard.draft.rules.calendarCustomization;res=store.generateCalendar(s,{preserveResults:false,alternate:wizard.alternate});}if(res.ok){clearCalendarDraft({silent:true});store.alignState(s);A.save(s);A.flash('#rulesMessage','Calendario creato solo dopo conferma. '+res.message,'ok');closeWizard({saveDraft:false});fill();render();}else{wizard.running=false;wizard.preview=res;renderWizard();A.flash('#rulesMessage',res.message,'error');}}

